import React, { useState } from "react";
import { useNavigate } from "react-router-dom";
import { signup } from "../services/api";
import { Box, Button, TextField, Typography, Alert, CircularProgress } from "@mui/material";

export default function Signup() {
  const navigate = useNavigate();
  const [form, setForm] = useState({ name: "", email: "", password: "", phone: "" });
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const handleChange = (e) => setForm({ ...form, [e.target.name]: e.target.value });

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");
    setLoading(true);

    try {
      await signup(form);
      alert("Signup successful! Please login.");
      navigate("/login");
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Box maxWidth={400} mx="auto" mt={5} p={3} boxShadow={3}>
      <Typography variant="h5" mb={2}>Signup</Typography>
      {error && <Alert severity="error">{error}</Alert>}
      <form onSubmit={handleSubmit}>
        <TextField fullWidth label="Name" name="name" margin="normal" onChange={handleChange} required />
        <TextField fullWidth label="Email" name="email" margin="normal" onChange={handleChange} required />
        <TextField fullWidth label="Password" name="password" type="password" margin="normal" onChange={handleChange} required />
        <TextField fullWidth label="Phone" name="phone" margin="normal" onChange={handleChange} />
        <Button type="submit" fullWidth variant="contained" color="primary" sx={{ mt: 2 }} disabled={loading}>
          {loading ? <CircularProgress size={24} /> : "Signup"}
        </Button>
      </form>
    </Box>
  );
}
